arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    chargeTime+=1
    if chargeProg=0 //Normal behavior
    {
      if x<oPlayer1.x {image_xscale=1}
      else {image_xscale=-1}
      
      direction=player_sprite_center()
      speed=runAcc
      
      if chargeTime>=chargeDelay
      {
        findTargetX=point_distance(x,y,oPlayer1.x,oPlayer1.y-26)
        if findTargetX<160
        {
          speed=0
          image_xscale=1
          image_angle=direction-225
          chargeTime=0
          chargeProg+=1
        }
      }
    }
    else if chargeProg=1 //Wait time
    {
      if chargeTime>=15
      {
        chargeTime=0
        chargeProg+=1
      }
    }
    else if chargeProg=2 //Charge sting
    {
      speed=runAcc*7.5
      if chargeTime>=25
      {
        image_angle=0
        chargeTime=0
        chargeProg=0
      }
    }
  }
  else {speed=0}
  enemyStepEvent()
}
else {speed=0}
